const TOTAL = 17560;

const LVL_ABBR: Record<string, string> = {
  chapter: "Ch", section: "Sec", subsection: "Sub",
  subtopic: "Sbt", indexEntry: "Idx",
};

const DIFF_LABEL: Record<number, string> = {
  1: "Intro",
  2: "Undergrad (gentle)",
  3: "Undergrad",
  4: "Advanced",
  5: "Specialist",
};

// ---- HELPERS --------------------------------------------------------------
function downloadBlob(filename: string, content: string, mime: string) {
  const blob = new Blob([content], { type: mime });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  setTimeout(() => {
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  }, 0);
}

function entryMatches(
  e: EntryTuple,
  search: string,
  bookFilter: string,
  diffFilter: string,
  topicFilter: string,
  exercisesOnly: boolean,
): boolean {
  if (bookFilter !== "all" && BOOKS[e[0]] !== bookFilter) return false;
  if (diffFilter !== "all" && e[7] !== parseInt(diffFilter, 10)) return false;
  if (topicFilter !== "all" && TOPICS[e[6]] !== topicFilter) return false;
  if (exercisesOnly && e[8] === null) return false;
  if (search) {
    const s = search.toLowerCase();
    if (
      !e[2].toLowerCase().includes(s) &&
      !(e[3] ?? "").toLowerCase().includes(s) &&
      !BOOKS[e[0]].toLowerCase().includes(s) &&
      !TOPICS[e[6]].toLowerCase().includes(s)
    ) return false;
  }
  return true;
}

function toMarkdown(filtered: EntryTuple[]): string {
  // Mirrors render_markdown() in render.py.
  const byTopic = new Map<number, EntryTuple[]>();
  for (const e of filtered) {
    const arr = byTopic.get(e[6]) ?? [];
    arr.push(e);
    byTopic.set(e[6], arr);
  }
  const out: string[] = [];
  const escMd = (s: string) => String(s ?? "").replace(/\|/g, "\\|");
  out.push("# Combined Index (filtered view)");
  out.push("");
  out.push(`Total: ${filtered.length} of ${TOTAL} entries.`);
  out.push("");
  for (let ti = 0; ti < TOPICS.length; ti++) {
    const rows = byTopic.get(ti);
    if (!rows || rows.length === 0) continue;
    const structural = rows.filter(isStructural);
    out.push(`## ${TOPICS[ti]}`);
    out.push("");
    out.push(`_${structural.length} reading entries + ${rows.length - structural.length} keyword entries._`);
    out.push("");
    if (structural.length > 0) {
      out.push("### Summary by book");
      out.push("");
      out.push("| Book | Pages | Description |");
      out.push("| --- | --- | --- |");
      for (const b of contributingBooks(rows)) {
        const bookRows = rows.filter(r => isStructural(r) && BOOKS[r[0]] === b);
        if (bookRows.length === 0) continue;
        out.push(`| ${b} | ${bookPageRangeOf(bookRows)} | ${escMd(descriptionForRows(bookRows))} |`);
      }
      out.push("");
      const { curated, others } = groupByConcept(rows, ti);
      const writeBlock = (label: string, rs: EntryTuple[]) => {
        out.push(`### ${label}  (${rs.length} rows)`);
        out.push("");
        out.push("| Diff | Book | Lvl | Book Pg | PDF Pg | Exer | Kind | Title | Path |");
        out.push("| :-: | --- | :-: | --: | --: | --: | :-: | --- | --- |");
        for (const r of rs) {
          const lvl = LVL_ABBR[LEVELS[r[1]]] ?? LEVELS[r[1]].slice(0, 3);
          const bp = r[4] ?? "";
          const pp = r[5] ?? "";
          const ex = r[8] ?? "";
          const kind = r[10] === 1 ? "Practical" : "Theory";
          out.push(`| ${r[7]} | ${BOOKS[r[0]]} | ${lvl} | ${bp} | ${pp} | ${ex} | ${kind} | ${escMd(r[2])} | ${escMd(r[3] ?? "")} |`);
        }
        out.push("");
      };
      for (const [label, rs] of curated) writeBlock(label, rs);
      if (others.length > 0) {
        out.push("### Other (auto-grouped)");
        out.push("");
        for (const [label, rs] of others) writeBlock(label, rs);
      }
    }
  }
  // Keywords appendix
  const allKw = filtered.filter(r => !isStructural(r));
  if (allKw.length > 0) {
    out.push("---");
    out.push("");
    out.push("# Appendix: Back-of-book index keywords");
    out.push("");
    const byBook = new Map<string, EntryTuple[]>();
    for (const r of allKw) {
      const b = BOOKS[r[0]];
      if (!byBook.has(b)) byBook.set(b, []);
      byBook.get(b)!.push(r);
    }
    for (const b of BOOKS) {
      const rs = byBook.get(b);
      if (!rs) continue;
      rs.sort((a, c) => (a[2] ?? "").toLowerCase().localeCompare((c[2] ?? "").toLowerCase()));
      out.push(`## ${b}`);
      out.push("");
      out.push(`_${rs.length} keywords._`);
      out.push("");
      out.push("| Book Pg | PDF Pg | Title |");
      out.push("| --: | --: | --- |");
      for (const r of rs) {
        out.push(`| ${r[4] ?? ""} | ${r[5] ?? ""} | ${escMd(r[2])} |`);
      }
      out.push("");
    }
  }
  return out.join("\n");
}

function toCsv(filtered: EntryTuple[]): string {
  const header = ["Book","Level","Difficulty","Kind","Topic","Concept","Title","Path","BookPage","PDFPage","Exercises"];
  const esc = (v: unknown) => {
    if (v === null || v === undefined) return "";
    const s = String(v);
    if (s.includes(",") || s.includes('"') || s.includes("\n")) {
      return '"' + s.replace(/"/g, '""') + '"';
    }
    return s;
  };
  const lines = [header.join(",")];
  for (const r of filtered) {
    const kind = r[10] === 1 ? "Practical" : "Theory";
    lines.push([
      BOOKS[r[0]], LEVELS[r[1]], r[7], kind, TOPICS[r[6]], r[9] || "",
      r[2], r[3] ?? "", r[4] ?? "", r[5] ?? "", r[8] ?? "",
    ].map(esc).join(","));
  }
  return lines.join("\n");
}

function toJson(filtered: EntryTuple[]): string {
  return JSON.stringify(filtered.map(r => ({
    book: BOOKS[r[0]],
    level: LEVELS[r[1]],
    title: r[2],
    path: r[3],
    bookPage: r[4],
    pdfPage: r[5],
    topicSection: TOPICS[r[6]],
    difficulty: r[7],
    exercisesBookPage: r[8],
    concept: r[9] || null,
    isPractical: r[10] === 1,
  })), null, 2);
}

